changeSet.sql:
-- ---- top-level content (homebrew-ownable) -------------------------------------------
ALTER TABLE equipment_item   ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE feat             ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE background       ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE character_class  ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE subclass         ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE spell            ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE species          ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE magic_item       ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);

-- ---- homebrew-ownable dictionaries -------------------------------------------------
ALTER TABLE damage_type        ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE ability_score      ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE skill              ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE currency           ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE magic_item_rarity  ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE magic_item_type    ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE character_size     ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);
ALTER TABLE equipment_category ADD COLUMN homebrew_id uuid REFERENCES homebrew_packages(id);

-- ---- top-level content: enforce homebrew slug uniqueness per package ----------------
-- (vanilla uniqueness is already enforced by the existing UNIQUE(mod_id, slug);
--  homebrew rows have mod_id NULL, so we need a dedicated partial index for them.)
CREATE UNIQUE INDEX uq_equipment_item_hb_slug  ON equipment_item (homebrew_id, slug)  WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_feat_hb_slug            ON feat (homebrew_id, slug)            WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_background_hb_slug      ON background (homebrew_id, slug)      WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_character_class_hb_slug ON character_class (homebrew_id, slug) WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_subclass_hb_slug        ON subclass (homebrew_id, slug)        WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_spell_hb_slug           ON spell (homebrew_id, slug)           WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_species_hb_slug         ON species (homebrew_id, slug)         WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_magic_item_hb_slug      ON magic_item (homebrew_id, slug)      WHERE homebrew_id IS NOT NULL;

-- ---- dictionaries: replace the global UNIQUE(slug) with split vanilla/homebrew rules -
ALTER TABLE damage_type        DROP CONSTRAINT damage_type_slug_key;
ALTER TABLE ability_score      DROP CONSTRAINT ability_score_slug_key;
ALTER TABLE skill              DROP CONSTRAINT skill_slug_key;
ALTER TABLE currency           DROP CONSTRAINT currency_slug_key;
ALTER TABLE magic_item_rarity  DROP CONSTRAINT magic_item_rarity_slug_key;
ALTER TABLE magic_item_type    DROP CONSTRAINT magic_item_type_slug_key;
ALTER TABLE character_size     DROP CONSTRAINT character_size_slug_key;
ALTER TABLE equipment_category DROP CONSTRAINT equipment_category_slug_key;

CREATE UNIQUE INDEX uq_damage_type_vanilla_slug        ON damage_type (slug)        WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_damage_type_hb_slug             ON damage_type (homebrew_id, slug)        WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_ability_score_vanilla_slug      ON ability_score (slug)      WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_ability_score_hb_slug           ON ability_score (homebrew_id, slug)      WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_skill_vanilla_slug              ON skill (slug)              WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_skill_hb_slug                   ON skill (homebrew_id, slug)              WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_currency_vanilla_slug           ON currency (slug)           WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_currency_hb_slug                ON currency (homebrew_id, slug)           WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_magic_item_rarity_vanilla_slug  ON magic_item_rarity (slug)  WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_magic_item_rarity_hb_slug       ON magic_item_rarity (homebrew_id, slug)  WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_magic_item_type_vanilla_slug    ON magic_item_type (slug)    WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_magic_item_type_hb_slug         ON magic_item_type (homebrew_id, slug)    WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_character_size_vanilla_slug     ON character_size (slug)     WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_character_size_hb_slug          ON character_size (homebrew_id, slug)     WHERE homebrew_id IS NOT NULL;
CREATE UNIQUE INDEX uq_equipment_category_vanilla_slug ON equipment_category (slug) WHERE homebrew_id IS NULL;
CREATE UNIQUE INDEX uq_equipment_category_hb_slug      ON equipment_category (homebrew_id, slug) WHERE homebrew_id IS NOT NULL;

-- ---- helpful lookup indexes for the vanilla-vs-homebrew resolver --------------------
CREATE INDEX idx_content_damage_type_hb        ON damage_type (homebrew_id);
CREATE INDEX idx_content_ability_score_hb      ON ability_score (homebrew_id);
CREATE INDEX idx_content_skill_hb              ON skill (homebrew_id);
CREATE INDEX idx_content_currency_hb           ON currency (homebrew_id);
CREATE INDEX idx_content_magic_item_rarity_hb  ON magic_item_rarity (homebrew_id);
CREATE INDEX idx_content_magic_item_type_hb    ON magic_item_type (homebrew_id);
CREATE INDEX idx_content_character_size_hb     ON character_size (homebrew_id);
CREATE INDEX idx_content_equipment_category_hb ON equipment_category (homebrew_id);

