ALTER TABLE magic_item       DROP COLUMN homebrew_id;
ALTER TABLE species          DROP COLUMN homebrew_id;
ALTER TABLE spell            DROP COLUMN homebrew_id;
ALTER TABLE subclass         DROP COLUMN homebrew_id;
ALTER TABLE character_class  DROP COLUMN homebrew_id;
